    int arr[7];
    int *p;
    int *q;
    arr[4] = 0x14;
    arr[5] = a1;
    p = *a0;
    q = (int *)p[0x28/4];
    if (q) {}
    ((void(*)(int, int*))q[0x2C/4])(
        *(short*)((char*)q + 0x28) + (int)p, &arr[4]);
